"""
Inventory management for the restaurant order processing system.

Tracks stock levels for menu items and handles reservation/deduction
of inventory during order processing.
"""

import threading
import time
from typing import Optional
from order_system.models import Order, OrderItem, OrderResult, OrderStatus


class InsufficientStockError(Exception):
    """Raised when there isn't enough stock to fulfill an order."""

    def __init__(self, item_name: str, requested: int, available: int):
        self.item_name = item_name
        self.requested = requested
        self.available = available
        super().__init__(
            f"Insufficient stock for '{item_name}': "
            f"requested {requested}, available {available}"
        )


class InventoryManager:
    """Manages inventory levels for the restaurant."""

    def __init__(self):
        self._stock: dict[str, int] = {}
        self._lock = threading.Lock()
        self._restock_threshold = 5
        self._low_stock_callbacks: list = []

    def set_stock(self, item_key: str, quantity: int) -> None:
        """Set the stock level for an item."""
        with self._lock:
            self._stock[item_key] = max(0, quantity)

    def get_stock(self, item_key: str) -> int:
        """Get current stock level for an item."""
        with self._lock:
            return self._stock.get(item_key, 0)

    def bulk_set_stock(self, stock_levels: dict[str, int]) -> None:
        """Set stock levels for multiple items at once."""
        with self._lock:
            for key, qty in stock_levels.items():
                self._stock[key] = max(0, qty)

    def check_availability(self, order: Order) -> list[str]:
        """
        Check if all items in the order are available in stock.

        Returns a list of error messages (empty if all items available).
        """
        errors = []
        with self._lock:
            # Aggregate quantities per item key
            required: dict[str, int] = {}
            for item in order.items:
                key = self._item_key(item)
                required[key] = required.get(key, 0) + item.quantity

            for key, needed in required.items():
                available = self._stock.get(key, 0)
                if available < needed:
                    errors.append(
                        f"Insufficient stock for '{key}': "
                        f"need {needed}, have {available}"
                    )
        return errors

    def deduct_stock(self, order: Order) -> dict[str, int]:
        """
        Deduct inventory for all items in the order.

        Returns a dict of item_key -> new stock level.
        """
        deducted = {}
        with self._lock:
            for item in order.items:
                key = self._item_key(item)
                current = self._stock.get(key, 0)
                new_level = current - item.quantity
                self._stock[key] = new_level
                deducted[key] = new_level

                if new_level <= self._restock_threshold:
                    self._trigger_low_stock_alert(key, new_level)

        return deducted

    def check_and_deduct(self, order: Order) -> dict[str, int]:
        """Atomically check availability and deduct stock."""
        with self._lock:
            required: dict[str, int] = {}
            for item in order.items:
                key = self._item_key(item)
                required[key] = required.get(key, 0) + item.quantity

            for key, needed in required.items():
                available = self._stock.get(key, 0)
                if available < needed:
                    raise InsufficientStockError(key, needed, available)

            deducted = {}
            for item in order.items:
                key = self._item_key(item)
                self._stock[key] -= item.quantity
                deducted[key] = self._stock[key]

            return deducted

    def on_low_stock(self, callback) -> None:
        """Register a callback for low stock alerts."""
        self._low_stock_callbacks.append(callback)

    def _trigger_low_stock_alert(self, item_key: str, level: int) -> None:
        """Notify registered callbacks about low stock."""
        for cb in self._low_stock_callbacks:
            try:
                cb(item_key, level)
            except Exception:
                pass  # Don't let callback errors break inventory ops

    def _item_key(self, item: OrderItem) -> str:
        """Generate a stock lookup key for an order item."""
        return item.menu_item.name.lower().replace(" ", "_")

    def get_all_stock(self) -> dict[str, int]:
        """Return a snapshot of all stock levels."""
        with self._lock:
            return dict(self._stock)

    def restock(self, item_key: str, quantity: int) -> int:
        """Add stock for an item. Returns new stock level."""
        with self._lock:
            current = self._stock.get(item_key, 0)
            self._stock[item_key] = current + quantity
            return self._stock[item_key]

"""
Order validation module for the restaurant order processing system.

Validates orders before they enter the processing pipeline, checking
item availability, quantity limits, customer info, and special instructions.
"""

from typing import Optional
from order_system.models import (
    Order,
    OrderItem,
    MenuItem,
    ItemCategory,
    flatten_modifiers,
)


# Validation constants
MAX_QUANTITY_PER_ITEM = 20
MAX_ITEMS_PER_ORDER = 50
MAX_SPECIAL_INSTRUCTIONS_LENGTH = 500
MAX_MODIFIER_DEPTH = 10
ALCOHOL_CUTOFF_HOUR = 22  # No alcohol orders after 10 PM
MIN_TABLE_NUMBER = 1
MAX_TABLE_NUMBER = 60


class ValidationError(Exception):
    """Raised when order validation fails."""

    def __init__(self, message: str, field: Optional[str] = None):
        self.message = message
        self.field = field
        super().__init__(self.message)


def validate_order(order: Order) -> list[str]:
    """
    Validate an order through all validation checks.

    Returns a list of validation error messages. An empty list means
    the order is valid.
    """
    errors = []

    # Check that the order has items
    if not order.items:
        errors.append("Order must contain at least one item")
        return errors

    # Check total item count
    if len(order.items) > MAX_ITEMS_PER_ORDER:
        errors.append(
            f"Order exceeds maximum of {MAX_ITEMS_PER_ORDER} line items"
        )

    # Validate customer name
    if not order.customer_name or not order.customer_name.strip():
        errors.append("Customer name is required")

    # Validate table number for dine-in orders
    if not order.is_takeout:
        if order.table_number is None:
            errors.append("Table number is required for dine-in orders")
        elif not (MIN_TABLE_NUMBER <= order.table_number <= MAX_TABLE_NUMBER):
            errors.append(
                f"Table number must be between {MIN_TABLE_NUMBER} and {MAX_TABLE_NUMBER}"
            )

    # Validate special instructions at order level
    cleaned_instructions = order.special_instructions.strip()
    if len(cleaned_instructions) > MAX_SPECIAL_INSTRUCTIONS_LENGTH:
        errors.append(
            f"Special instructions exceed {MAX_SPECIAL_INSTRUCTIONS_LENGTH} characters"
        )

    # Validate each item in the order
    for i, item in enumerate(order.items):
        item_errors = _validate_order_item(item, i)
        errors.extend(item_errors)

    return errors


def _validate_order_item(item: OrderItem, index: int) -> list[str]:
    """Validate a single order item."""
    errors = []
    prefix = f"Item {index + 1} ({item.menu_item.name})"

    # Check availability
    if not item.menu_item.available:
        errors.append(f"{prefix}: Item is currently unavailable")

    # Check quantity
    if item.quantity < 1:
        errors.append(f"{prefix}: Quantity must be at least 1")
    elif item.quantity > MAX_QUANTITY_PER_ITEM:
        errors.append(
            f"{prefix}: Quantity exceeds maximum of {MAX_QUANTITY_PER_ITEM}"
        )

    # Check price sanity
    if item.menu_item.base_price <= 0:
        errors.append(f"{prefix}: Invalid price")

    # Validate modifiers if present
    if item.modifiers:
        mod_errors = _validate_modifiers(item.modifiers, prefix)
        errors.extend(mod_errors)

    # Validate item-level special instructions
    if item.special_instructions is not None:
        if len(item.special_instructions.strip()) > MAX_SPECIAL_INSTRUCTIONS_LENGTH:
            errors.append(
                f"{prefix}: Special instructions too long"
            )

    # Alcohol time restrictions
    if item.menu_item.category == ItemCategory.ALCOHOL:
        _check_alcohol_restrictions(item, prefix, errors)

    return errors


def _validate_modifiers(
    modifiers: dict, prefix: str, depth: int = 0
) -> list[str]:
    """
    Validate modifier dictionary structure and values.
    """
    errors = []

    if depth > MAX_MODIFIER_DEPTH:
        errors.append(f"{prefix}: Modifier nesting exceeds maximum depth")
        return errors

    for key, value in modifiers.items():
        if not isinstance(key, str):
            errors.append(f"{prefix}: Modifier keys must be strings")
            continue

        if isinstance(value, dict):
            nested_errors = _validate_modifiers(value, prefix, depth + 1)
            errors.extend(nested_errors)
        elif isinstance(value, (list, tuple)):
            for element in value:
                if isinstance(element, dict):
                    nested_errors = _validate_modifiers(
                        element, prefix, depth + 1
                    )
                    errors.extend(nested_errors)

    return errors


def _check_alcohol_restrictions(
    item: OrderItem, prefix: str, errors: list[str]
) -> None:
    """Check time-based restrictions for alcohol orders."""
    from datetime import datetime

    current_hour = datetime.now().hour
    if current_hour >= ALCOHOL_CUTOFF_HOUR:
        errors.append(
            f"{prefix}: Alcohol orders not accepted after {ALCOHOL_CUTOFF_HOUR}:00"
        )


def validate_menu_item(item: MenuItem) -> list[str]:
    """Validate a menu item definition."""
    errors = []

    if not item.name or not item.name.strip():
        errors.append("Menu item name is required")

    if item.base_price < 0:
        errors.append("Price cannot be negative")

    if item.prep_time_minutes < 0:
        errors.append("Prep time cannot be negative")

    return errors
